const xml = $input.item.json.data || $input.item.json.body || '';
const urls = [];
const regex = /<loc>([^<]+)<\/loc>/g;
let match;
while ((match = regex.exec(xml)) !== null) {
  urls.push(match[1]);
}
return urls.slice(0, 50).map(url => ({ json: { url, client_id: $('Fetch Client').item.json[0].id, domain: $('Fetch Client').item.json[0].domain } }));

const url = $('Batch URLs').item.json;
const psi = $input.item.json;

const lhr = psi.lighthouseResult || {};
const categories = lhr.categories || {};
const audits = lhr.audits || {};

const perfScore = (categories.performance?.score || 0) * 100;
const lcp = audits['largest-contentful-paint']?.numericValue || null;
const fid = audits['max-potential-fid']?.numericValue || null;
const cls = audits['cumulative-layout-shift']?.numericValue || null;
const ttfb = audits['server-response-time']?.numericValue || null;

const issues = [];
if (perfScore < 50) issues.push({ type: 'slow_page', severity: 'critical', desc: `Performance score ${perfScore}/100` });
else if (perfScore < 90) issues.push({ type: 'slow_page', severity: 'warning', desc: `Performance score ${perfScore}/100` });
if (lcp && lcp > 4000) issues.push({ type: 'high_lcp', severity: 'critical', desc: `LCP ${(lcp/1000).toFixed(1)}s exceeds 4s threshold` });
if (cls && cls > 0.25) issues.push({ type: 'high_cls', severity: 'warning', desc: `CLS ${cls.toFixed(3)} exceeds 0.25 threshold` });

return [{ json: { ...url, perfScore, lcp, fid, cls, ttfb, issues } }];
